+	return streamClusters(c, h, sseClusterStreamConfig{
+		demoKey:        "nodes",
+		clusterTimeout: 15 * time.Second,
+	}, func(ctx context.Context, cluster string) (interface{}, error) {
+		return h.k8sClient.GetNodes(ctx, cluster)
+	})
+}
